mapper.update:
update night_execution_tasks set 
where task_id=#{taskId} and status='SCHEDULED'
and target_linux_server_id=#{expectedTargetLinuxServerId}
and state_version=#{expectedStateVersion}

update night_execution_tasks set 
where task_id=#{taskId} and status='DISPATCHING'
and dispatch_attempt_id=#{expectedAttemptId}

update night_execution_tasks
set dispatch_lease_until=#{leaseUntil}, updated_at=#{now}
where task_id=#{taskId} and status='DISPATCHING'
and dispatch_attempt_id=#{attemptId}
and window_end > #{now}

mapper.select:
select  from night_execution_tasks
where owner_user_id=#{ownerUserId} and status in ('SCHEDULED','DISPATCHING')
order by slot_start, created_at, task_id limit #{limit} offset #{offset}

select  from night_execution_tasks
where status='SCHEDULED' and slot_start <= #{now} and window_end > #{now}
order by slot_start, created_at, task_id limit #{limit}

select  from night_execution_tasks
where status='SCHEDULED' and window_end <= #{now}
order by window_end, created_at, task_id limit #{limit}

select  from night_execution_tasks
where status='DISPATCHING' and dispatch_lease_until <= #{cutoff}
order by dispatch_lease_until, created_at, task_id limit #{limit}

select  from night_execution_tasks
where status='DISPATCHING' and dispatch_owner_backend_process_id=#{backendProcessId}
order by dispatch_lease_until, created_at, task_id limit #{limit}

select  from night_execution_tasks
where status in ('DISPATCHED','CANCELLED','FAILED') and updated_at <= #{cutoff}
order by updated_at limit #{limit}

mapper.insert:
insert into night_execution_slot_reservations(slot_start,reserved_count,updated_at)
select #{slotStart},0,#{now}
where not exists (
select 1 from night_execution_slot_reservations where slot_start=#{slotStart}
)

mapper.update:
update night_execution_slot_reservations
set reserved_count=reserved_count+1, updated_at=#{now}
where slot_start=#{slotStart} and reserved_count < #{capacity}

update night_execution_slot_reservations
set reserved_count=case when reserved_count > 0 then reserved_count-1 else 0 end, updated_at=#{now}
where slot_start=#{slotStart}

mapper.insert:
insert into night_execution_session_locks(session_id,task_id,owner_user_id,created_at)
select #{sessionId},#{taskId},#{ownerUserId},#{now}
where not exists (
select 1 from night_execution_session_locks where session_id=#{sessionId} or task_id=#{taskId}
)

mapper.delete:
delete from night_execution_tasks
where task_id=#{taskId}
  and state_version=#{stateVersion}
  and status in ('DISPATCHED','CANCELLED','FAILED')
  and updated_at <= #{cutoff}
